mapper.select:
select m.*
from sys_menu m

    m.status = 0

        and m.menu_type != #{request.menuType}


        and m.title = #{request.title}


order by m.parent_id, m.order_num

select distinct m.* from sys_menu m left join sys_role_menu rm on m.menu_id = rm.menu_id left join sys_user_role ur on rm.role_id = ur.role_id left join sys_role ro on rm.role_id = ro.role_id where ur.user_id = #{request.userId} and m.status = 0 and ro.status = 0
and m.menu_type != #{request.menuType}
and m.title != #{request.title}
order by m.parent_id, m.order_num

select distinct m.*
from sys_menu m
left join sys_role_menu rm on m.menu_id = rm.menu_id
left join sys_user_role ur on rm.role_id = ur.role_id
left join sys_role ro on ur.role_id = ro.role_id


        ur.user_id = #{params.userId}


        AND m.menu_name like concat('%', #{title}, '%')


        AND m.visible = #{visible}


        AND m.status = #{status}


order by m.parent_id, m.order_num

select m.menu_id from sys_menu m left join sys_role_menu rm on m.menu_id = rm.menu_id where rm.role_id = #{roleId}
and m.menu_id not in (select m.parent_id from sys_menu m inner join sys_role_menu rm on m.menu_id = rm.menu_id and rm.role_id = #{roleId})
order by m.parent_id, m.order_num



    1 = 1

        AND title like concat('%', #{title}, '%')


        AND visible = #{visible}


        AND parent_Id = #{parentId}


        AND status = #{status}


order by parent_id, order_num
